//refAssemblies: TCAdmin.SDK.dll, TCAdmin.GameHosting.SDK.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE


Globals.ThisService.Variables["ClusterPath"] = System.Environment.GetEnvironmentVariable("HOME");

using System;
using System.IO;
using System.Linq;
using TCAdmin.SDK.Database.Entities;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

long selectedCmdLineId = -1;
if(Globals.ThisService.Variables.ContainsKey("__SelectedCmdLine") )
{
    var selectedCmdLineParts = Globals.ThisService.Variables.Parse<string>("__SelectedCmdLine").Split(":");
    if(selectedCmdLineParts[0] == "CUS")  selectedCmdLineId = long.Parse(selectedCmdLineParts[1]);
}
// Cluster id is set in custom command line. Exit if no custom command line is selected.
if(selectedCmdLineId == -1)
{
    Globals.ScriptConsole.WriteLine("Didn't find a selected custom command line");
    return;
}

if(Globals.ThisService.CustomCommandLines == null)
{
    await Globals.GameServiceManager.TCAdminDbContext.Entry<GameService>(Globals.ThisService).Collection(x=>x.CustomCommandLines).LoadAsync();
}

var selectedCmdLine = Globals.ThisService.CustomCommandLines.SingleOrDefault(x=>x.CmdLineId == selectedCmdLineId);

if(selectedCmdLine == null)
{
    Globals.ScriptConsole.WriteLine($"Custom command line with id {selectedCmdLineId} does not exist");
    return;
}

// Exit if cluster id is not set in the custom command line.
var clusterId = selectedCmdLine.Variables.ContainsKey("clusterid") ? selectedCmdLine.Variables.Parse<string>("clusterid") : null;
if(string.IsNullOrWhiteSpace(clusterId))
{
    Globals.ScriptConsole.WriteLine("clusterId not set");
    return;
}

var clusterPath = Globals.ThisService.Variables.Parse<string>("ClusterPath");

if (string.IsNullOrWhiteSpace(clusterPath))
{
    throw new Exception("Your service has no ClusterPath set. Go to \"Advanced\" and click \"Set ClusterPath value\"");
}

string clusterFolder = clusterPath + "/clusters";

if (!Directory.Exists(clusterFolder))
{
    Directory.CreateDirectory(clusterFolder);
}

var runas = Globals.ServiceManagerService.GetServiceCredential(Globals.ThisService.ServiceId).UserName;
Globals.OperatingSystem.SetDirectoryOwner(clusterFolder, Environment.GetEnvironmentVariable("COMPUTERNAME"), runas, true);

Globals.ScriptConsole.WriteLine($"Cluster path is configured correctly at {(new DirectoryInfo(clusterFolder)).FullName}");

