using System;
using System.IO;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Temp SteamCMD workshop files can take up a lot of space. Clean them up after the server stops.

string rootDir = ThisService.RootDirectory;

// ARK's workshop cache path is deep enough to exceed Windows MAX_PATH during delete,
// so rename the content folder to a short name first, then delete.
string longWorkshopPath  = Path.Combine(rootDir, "Engine", "Binaries", "ThirdParty", "SteamCMD", "Win64", "steamapps", "workshop", "content", "346110");
string shortWorkshopPath = Path.Combine(rootDir, "Engine", "Binaries", "ThirdParty", "SteamCMD", "Win64", "s");

if (Directory.Exists(longWorkshopPath))
{
    try
    {
        Directory.Move(longWorkshopPath, shortWorkshopPath);
    }
    catch (IOException ex)
    {
        throw new Exception($"An error occurred. Please contact support. Error was: {ex.Message}", ex);
    }
}

if (Directory.Exists(shortWorkshopPath))
{
    try
    {
        Directory.Delete(shortWorkshopPath, true);
    }
    catch (IOException ex)
    {
        throw new Exception($"Could not delete Engine/Binaries/ThirdParty/SteamCMD/Win64/s/. Please contact support. Error was: {ex.Message}", ex);
    }
}

string nestedSteamApps = Path.Combine(rootDir, "Engine", "Binaries", "ThirdParty", "SteamCMD", "Win64", "steamapps");
if (Directory.Exists(nestedSteamApps))
{
    try
    {
        Directory.Delete(nestedSteamApps, true);
    }
    catch (IOException ex)
    {
        throw new Exception($"Could not delete Engine/Binaries/ThirdParty/SteamCMD/Win64/steamapps/. Please contact support. Error was: {ex.Message}", ex);
    }
}

string rootSteamAppsWorkshop = Path.Combine(rootDir, "steamapps", "workshop");
if (Directory.Exists(rootSteamAppsWorkshop))
{
    try
    {
        Directory.Delete(rootSteamAppsWorkshop, true);
    }
    catch (IOException ex)
    {
        throw new Exception($"Could not delete steamapps/workshop. Please contact support. Error was: {ex.Message}", ex);
    }
}

