// --- Helpers ---

// UE4 string read: int32 length, UTF-8 bytes, trailing null. Negative length is a
// UTF-16 flag the original Python didn't decode — we preserve that by returning
// "" without advancing the stream, which matches V2 behavior on ARK's files.
string ReadUe4String(BinaryReader reader)
{
    int count = reader.ReadInt32();
    if (count <= 0) return "";
    byte[] raw = reader.ReadBytes(count);
    return Encoding.UTF8.GetString(raw, 0, raw.Length - 1);
}

// UE4 string write: int32 length-including-null, UTF-8 bytes, one null byte.
void WriteUe4String(string s, BinaryWriter writer)
{
    byte[] bytes = Encoding.UTF8.GetBytes(s);
    writer.Write(bytes.Length + 1);
    writer.Write(bytes);
    writer.Write((byte)0);
}

// ARK .z format: 8B magic, 8B chunk_size, 8B unused, 8B total_uncompressed,
// then N pairs of (8B compressed_size, 8B uncompressed_size), then N zlib chunks.
// -1641380927 is a sentinel meaning "use 128 KiB chunks".
void ZUnpack(string src, string dst)
{
    using var srcStream = File.OpenRead(src);
    using var dstStream = File.Create(dst);
    using var reader = new BinaryReader(srcStream);

    reader.ReadBytes(8);
    long size1 = reader.ReadInt64();
    reader.ReadBytes(8);
    long size2 = reader.ReadInt64();
    if (size1 == -1641380927L) size1 = 131072L;
    long runs = (size2 + size1 - 1) / size1;

    var chunkSizes = new long[runs];
    for (int i = 0; i < runs; i++)
    {
        chunkSizes[i] = reader.ReadInt64();
        reader.ReadBytes(8);
    }

    for (int i = 0; i < runs; i++)
    {
        byte[] compressed = reader.ReadBytes((int)chunkSizes[i]);
        using var inflate = new ZLibStream(new MemoryStream(compressed), CompressionMode.Decompress);
        inflate.CopyTo(dstStream);
    }
}

List<string> ParseBaseInfo(string modIdFolder)
{
    string modInfoPath = Path.Combine(modIdFolder, "mod.info");
    if (!File.Exists(modInfoPath))
        throw new FileNotFoundException($"mod.info not found at '{modInfoPath}'.", modInfoPath);

    using var stream = File.OpenRead(modInfoPath);
    using var reader = new BinaryReader(stream);

    ReadUe4String(reader); // mod name — unused
    int mapCount = reader.ReadInt32();
    var maps = new List<string>(mapCount);
    for (int i = 0; i < mapCount; i++)
    {
        string curMap = ReadUe4String(reader);
        if (!string.IsNullOrEmpty(curMap)) maps.Add(curMap);
    }
    return maps;
}

Dictionary<string, string> ParseMetaData(string modIdFolder)
{
    string modMetaPath = Path.Combine(modIdFolder, "modmeta.info");
    if (!File.Exists(modMetaPath))
        throw new FileNotFoundException($"modmeta.info not found at '{modMetaPath}'.", modMetaPath);

    ScriptConsole.WriteLine("[+] Collecting Mod Meta Data From modmeta.info");

    using var stream = File.OpenRead(modMetaPath);
    using var reader = new BinaryReader(stream);

    int totalPairs = reader.ReadInt32();
    var meta = new Dictionary<string, string>(totalPairs);
    for (int i = 0; i < totalPairs; i++)
    {
        string key = ReadUe4String(reader);
        string value = ReadUe4String(reader);
        if (!string.IsNullOrEmpty(key) && !string.IsNullOrEmpty(value))
        {
            ScriptConsole.WriteLine($"[!] {key}:{value}");
            meta[key] = value;
        }
    }
    return meta;
}

void CreateModFile(long modId, string modsFolder, List<string> maps, Dictionary<string, string> meta)
{
    string outPath = Path.Combine(modsFolder, $"{modId}.mod");
    using var stream = File.Create(outPath);
    using var writer = new BinaryWriter(stream);

    // Ids above int32.MaxValue wrap around into the negative signed range — ARK
    // reads the id as a signed int32, so anything larger must be bit-pattern-identical.
    int modIdInt = unchecked((int)modId);
    writer.Write(modIdInt);
    writer.Write(new byte[4]); // 'ixxxx' — int followed by 4 padding bytes

    WriteUe4String("ModName", writer);
    WriteUe4String("", writer);

    writer.Write(maps.Count);
    foreach (var m in maps) WriteUe4String(m, writer);

    writer.Write(4280483635u); // magic — origin unknown, preserved from reference script
    writer.Write(2);           // version marker — preserved from reference script

    // The original Python used struct.pack('p', mod_type); for the default
    // size-1 Pascal format this always emits \x00 regardless of mod_type. ARK
    // evidently accepts that, so we preserve the byte-for-byte output.
    writer.Write((byte)0);

    writer.Write(meta.Count);
    foreach (var kv in meta)
    {
        WriteUe4String(kv.Key, writer);
        WriteUe4String(kv.Value, writer);
    }
}

async Task ReportProgress(int? progress, string log = null)
{
    if (ThisTaskStepHandler != null)
        await ThisTaskStepHandler.UpdateProgress(progress, log);
    else if (!string.IsNullOrEmpty(log))
        ScriptConsole.WriteLine(log);
}

// --- Main flow ---

// Game OS (not host OS) drives file-layout decisions — V3 supports Windows games
// on Linux hosts (Wine) and Linux games on Windows hosts (WSL).
bool isWindowsGame = ThisGame.OperatingSystem == EOperatingSystem.Windows;

string preferred = isWindowsGame ? "WindowsNoEditor" : "LinuxNoEditor";
string fallback  = isWindowsGame ? "LinuxNoEditor"  : "WindowsNoEditor";
string noEditor = Path.Combine(installPath, preferred);
if (!Directory.Exists(noEditor))
{
    noEditor = Path.Combine(installPath, fallback);
    if (!Directory.Exists(noEditor))
        throw new DirectoryNotFoundException(
            $"Neither '{preferred}' nor '{fallback}' exists under '{installPath}'.");
}

var zFiles = Directory.GetFiles(noEditor, "*.z", SearchOption.AllDirectories);
int totalFileCount = zFiles.Length;
int extractedCount = 0;
int lastFileProgress = 0;
object progressLock = new();

await ReportProgress(0, $"Extracting {totalFileCount} files...");

await Parallel.ForEachAsync(
    zFiles,
    new ParallelOptions { MaxDegreeOfParallelism = 2, CancellationToken = ThisCancellationToken },
    async (zfile, ct) =>
    {
        string outFile = Path.Combine(Path.GetDirectoryName(zfile)!, Path.GetFileNameWithoutExtension(zfile));
        ZUnpack(zfile, outFile);
        ScriptConsole.WriteLine($"Extracted {outFile.Replace(ThisService.RootDirectory, "")}");
        File.Delete(zfile);
        File.Delete(zfile + ".uncompressed_size"); // no-op if missing

        int current = Interlocked.Increment(ref extractedCount);
        int pct = (int)Math.Round((double)current / totalFileCount * 100);
        bool shouldUpdate = false;
        lock (progressLock)
        {
            if (pct > lastFileProgress + 4) { lastFileProgress = pct; shouldUpdate = true; }
        }
        if (shouldUpdate) await ReportProgress(pct);
    });

// Move the extracted folder into ShooterGame/Content/Mods/{fileId}, replacing any previous install.
string modFolder = Path.Combine(ThisService.RootDirectory, $"ShooterGame/Content/Mods/{fileId}");
if (Directory.Exists(modFolder)) Directory.Delete(modFolder, true);
Directory.Move(noEditor, modFolder);

// Register the mod in GameUserSettings.ini → ActiveMods= (append if missing).
string serverOs = isWindowsGame ? "WindowsServer" : "LinuxServer";
string iniFile = Path.Combine(ThisService.RootDirectory, $"ShooterGame/Saved/Config/{serverOs}/GameUserSettings.ini");
if (File.Exists(iniFile))
{
    string fileContents = await File.ReadAllTextAsync(iniFile, ThisCancellationToken);
    var match = Regex.Match(fileContents, @"ActiveMods[ \t]*=[ \t]*(?<ActiveMods>[0-9, \t]*)", RegexOptions.IgnoreCase);
    if (match.Success)
    {
        string activeMods = match.Groups["ActiveMods"].Value;
        if (string.IsNullOrEmpty(activeMods) || activeMods.IndexOf(fileId.ToString(), StringComparison.Ordinal) == -1)
        {
            if (activeMods.Length > 0)
            {
                string newActive = activeMods + "," + fileId;
                fileContents = fileContents.Replace(activeMods, newActive);
            }
            else
            {
                int insertAt = match.Groups["ActiveMods"].Index;
                fileContents = fileContents.Substring(0, insertAt) + fileId + fileContents.Substring(insertAt);
            }
            await File.WriteAllTextAsync(iniFile, fileContents, ThisCancellationToken);
        }
    }
}

// Build the .mod file from mod.info + modmeta.info.
var maps = ParseBaseInfo(modFolder);
var meta = ParseMetaData(modFolder);
string modsDir = Path.Combine(ThisService.RootDirectory, "ShooterGame/Content/Mods");
CreateModFile(fileId, modsDir, maps, meta);

// Clean up the staging install directory.
if (Directory.Exists(installPath)) Directory.Delete(installPath, true);

await ReportProgress(100, "Mod installation complete.");

